","LOTUS_GIT_COMMIT":"9d3ab97d7ce8a9ec7b0f3ba14d84f1b9924ed029","MAX_POSTS_PER_PAGE":50,"ROLLBAR_ENV":"production","ROLLBAR_FE_ENABLED":true,"ROLLBAR_POST_CLIENT_ITEM_TOKEN":"fb557f59a5a84ab788801dd742eacf34","ROLLBAR_FILTER_HYDRATION_ERRORS":true,"GOOGLE_PICKER_APP_ID":"594601915089","GOOGLE_PICKER_DEVELOPER_KEY":"AIzaSyBeoz4WOjOsy8ZJFIkkQBvL8BZQCzLplHQ","GOOGLE_PICKER_CLIENT_ID":"594601915089-7c2994029qkt5qu2tmbppujr9jqrqqrs.apps.googleusercontent.com","DROPBOX_CHOOSER_API_KEY":"mh9jyh4mfwjnfhj","GOOGLE_RECAPTCHA_INVISIBLE_KEY":"6LfmcbcpAAAAAChNTbhUShzUOAMj_wY9LQIvLFX0","GOOGLE_RECAPTCHA_ENDPOINT":"https://www.recaptcha.net/recaptcha/enterprise.js","JOB_SEEKERS_URL":"https://my.greenhouse.io","SNOWPLOW_APP_ID":"job-board-renderer","SNOWPLOW_ENABLED":true,"SNOWPLOW_ENDPOINT":"spl.greenhouse.io","SNOWPLOW_NAMESPACE":"job-board-renderer-tracker","SNOWPLOW_DEBUG":false},"boardConfiguration":{"job_board_id":4001440002,"logo":{"href":"https://www.careem.com/","url":"https://s2-recruiting.cdn.greenhouse.io/external_greenhouse_job_boards/logos/400/144/000/original/Careem_Newbranding_CareemLogo_1024x512.jpg?1683707025"},"filters":{"include_office_filter":true,"include_department_filter":true,"allow_custom_field_filters":false},"button_shape":"pill","cta_text":"Apply","primary_font":"Untitled Sans","secondary_font":"Untitled Sans","custom_primary_font_url":null,"custom_secondary_font_url":null,"dropdown_selection_color":"#c4d6f3","active_field_color":"#709ce2","link_color":"#3d74cc","list_selection_color":"#d5e2f6","primary_font_color":"#3d74cc","outside_label":false,"view_all_link":false,"button_color":"#578bdd","button_hover_color":"#709ce2","button_text_color":"#000000","banner_url":null,"board_layout":"stacked","display_department_hierarchy":true,"hide_app_description":false,"header_text":"Current openings at Careem","job_board_public_url":"https://jobs.careem.com/","secondary_font_color":"#262626","background_color":"#ffffff","disable_captcha":false,"disable_eeoc_quick_apply":false,"display_departments":true,"display_search_bar":true,"display_new_jobs_tag":true,"display_number_of_open_jobs":true,"display_footer":true,"candidate_portal_enabled":true,"application_tracking_enabled":false,"seek_id":"","enable_recruitics":true,"appcast_tracking_code":null,"google_drive_enabled":true,"enable_dropbox":true,"allow_external_notifications":true,"display_job_trust_profiles":false,"grayscale_ai_bot_enabled":false,"grayscale_ai_bot_access_token":null},"urlToken":"careem","embedded":false,"isJobPost":true},"routes/$url_token_.jobs_.$job_post_id":{"jobPost":{"post_type":"job_post","language":"en","title":"Associate Director of Pricing - Quik","hiring_plan_id":6372076002,"content":"\u003cp\u003e\u003cstrong\u003e\u003cspan style=\"font-size: 10pt;\"\u003eAbout the Role\u003c/span\u003e\u003cbr\u003e\u003c/strong\u003e\u003cbr\u003eAs the \u003cstrong\u003eAssociate Director of Pricing\u003c/strong\u003e, you will own the strategic roadmap for how we price essential grocery items across our diverse markets. This isn't just about managing a spreadsheet; it’s about treating pricing as a \u003cstrong\u003estrategic lever\u003c/strong\u003e to drive growth, customer loyalty, and sustainable margins. You will have the autonomy to build a best-in-class pricing engine from the ground up for one of the region's fastest-growing grocery platforms. You’ll be at the intersection of commercial strategy and cutting-edge product development.\u0026nbsp;You will lead the transition from manual pricing to a sophisticated, productized, and automated ecosystem. We are looking for a data-driven leader who can balance the \"art\" of competitive retail with the \"science\" of algorithmic automation.\u003c/p\u003e\n\u003ch3\u003e\u003cspan style=\"font-size: 10pt;\"\u003e\u003cstrong\u003eWhat you'll do\u003c/strong\u003e\u003c/span\u003e\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e\u003cstrong\u003eStrategic Vision:\u003c/strong\u003e Design and execute the long-term pricing strategy for Careem Quik across multiple markets, ensuring alignment with regional consumer behaviors and business goals.\u003c/li\u003e\n\u003cli\u003e\u003cstrong\u003eProduct \u0026amp; Tech Partnership:\u003c/strong\u003e Collaborate deeply with Product and Engineering teams to build \"productized pricing\"—moving away from manual inputs toward automated, scalable systems.\u003c/li\u003e\n\u003cli\u003e\u003cstrong\u003eExperimental Frameworks:\u003c/strong\u003e Design and lead rigorous pricing experiments to quantify \u003cstrong\u003eprice elasticity\u003c/strong\u003e and consumer sensitivity, using these insights to refine our value proposition.\u003c/li\u003e\n\u003cli\u003e\u003cstrong\u003eCommercial Optimization:\u003c/strong\u003e Partner with the Commercial and Category teams to strike the perfect balance between \u003cstrong\u003emarket competitiveness\u003c/strong\u003e and \u003cstrong\u003ebottom-line margins\u003c/strong\u003e.\u003c/li\u003e\n\u003cli\u003e\u003cstrong\u003eExecution Oversight:\u003c/strong\u003e Ensure that the central strategy is localized and implemented accurately across all operating territories.\u003c/li\u003e\n\u003cli\u003e\u003cstrong\u003ePerformance Analytics:\u003c/strong\u003e Monitor daily pricing health, identifying opportunities for margin expansion without sacrificing our \"best-in-market\" promise for essential goods.\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch3\u003e\u003cspan style=\"font-size: 10pt;\"\u003e\u003cstrong\u003eWhat you'll need\u003c/strong\u003e\u003c/span\u003e\u003c/h3\u003e\n\u003cul\u003e\n\u003cli\u003e\u003cstrong\u003eExperience:\u003c/strong\u003e Minimum \u003cstrong\u003e8+ years\u003c/strong\u003e in Pricing, Revenue Management, or Strategy, specifically within \u003cstrong\u003eGrocery (Offline or E-commerce)\u003c/strong\u003e, FMCG, or High-Frequency Retail.\u003c/li\u003e\n\u003cli\u003e\u003cstrong\u003eData Mastery:\u003c/strong\u003e Expert-level proficiency in data analytics (SQL, Python, or R preferred). You should be comfortable navigating large datasets to extract actionable elasticity models.\u003c/li\u003e\n\u003cli\u003e\u003cstrong\u003eAutomation Mindset:\u003c/strong\u003e Proven track record of working with tech teams to automate pricing workflows and implement dynamic pricing logic.\u003c/li\u003e\n\u003cli\u003e\u003cstrong\u003eStrategic Thinker:\u003c/strong\u003e You see pricing as a tool for market share and customer lifetime value, not just a tactical cost-plus calculation.\u003c/li\u003e\n\u003cli\u003e\u003cstrong\u003eCommunication:\u003c/strong\u003e Ability to translate complex analytical findings into clear strategic recommendations for C-suite stakeholders.\u003c/li\u003e\n\u003cli\u003e\u003cstrong\u003eAdaptability:\u003c/strong\u003e Experience managing pricing across multiple geographical markets with varying competitive landscapes.\u003c/li\u003e\n\u003c/ul\u003e\n\u003cp\u003e\u003cstrong\u003eWhat we’ll provide you\u003c/strong\u003e\u003c/p\u003e\n\u003cp\u003eWe offer colleagues the opportunity to drive impact in the region while they learn and grow. As a full time Careem colleague, you will be able to:\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003eWork and learn from great minds by joining a community of inspiring colleagues.\u003c/li\u003e\n\u003cli\u003ePut your passion to work in a purposeful organisation dedicated to creating impact in a region with a lot of untapped potential.\u003c/li\u003e\n\u003cli\u003eExplore new opportunities to learn and grow every day.\u003c/li\u003e\n\u003cli\u003eWork 4 days a week in office \u0026amp; 1 day from home, and remotely from any country in the world for 30 days a year with unlimited vacation days per year. (If you are in an individual contributor role in tech, you will have 2 office days a week and 3 to work from home.)\u003c/li\u003e\n\u003cli\u003eAccess to healthcare benefits and fitness reimbursements for health activities including gym, health club, and training classes.\u003c/li\u003e\n\u003c/ul\u003e\n\u003cp\u003e\u0026nbsp;\u003c/p\u003e","introduction":"\u003cp\u003e\u003cspan style=\"font-family: helvetica, arial, sans-serif; font-size: 12pt;\"\u003eCareem is building the Everything App for the greater Middle East — making it easy to move around, order food and groceries, manage payments, and more. Our purpose is simple: to simplify and improve people’s lives and build an awesome organisation that inspires.\u003c/span\u003e\u003cbr\u003e\u003cspan style=\"font-family: helvetica, arial, sans-serif; font-size: 12pt;\"\u003eSince 2012, Careem has enabled earnings for over 2.5 million Captains, simplified the lives of more than 70 million customers, and built a platform where the region’s best talent and entrepreneurs thrive. We operate in 70+ cities across 10 countries, from Morocco to Pakistan.\u003c/span\u003e\u003c/p\u003e\n\u003cp\u003e\u003cspan style=\"font-family: helvetica, arial, sans-serif; font-size: 12pt;\"\u003e\u003cstrong data-stringify-type=\"bold\"\u003e\u003cem data-stringify-type=\"italic\"\u003eWe’re now entering our next chapter — one powered by AI. We’re looking for AI talent: curious problem-solvers who know how to apply AI to build tools, automate workflows, and create real impact. Whether it’s streamlining operations, enhancing customer experience, or reimagining internal systems — we want people who can make Careem work smarter and move faster.\u003c/em\u003e\u003c/strong\u003e\u003c/span\u003e\u003c/p\u003e","conclusion":"","enable_eeoc":false,"job_post_location":"Dubai, United Arab Emirates","public_url":"https://boards.greenhouse.io/careem/jobs/8441647002?gh_jid=8441647002","company_name":"Careem","confirmation_message":"\u003cp\u003eWe are thrilled that you are interested to be part of Careem!\u003cbr\u003e\u003cbr\u003eWe have received your application and one of our Recruiters will review it. Due to the volume of applications, we are unable to give a response to all applications, and prioritize the ones that meet the role requirements. Check out our careers page for the role that may be the best match for your experience - www.careem.com/careers\u003c/p\u003e\n\u003cp\u003eTalent Acquisition | Careem\u003c/p\u003e\n\u003cp\u003e\u0026nbsp;\u003c/p\u003e","pay_ranges":[],"published_at":"2026-03-10T08:45:39-04:00","employment":"hidden","fingerprint":"21aead92285f12fa3960ff33fd598280b1b0d123","redirect_to":null,"is_featured":false,"ai_disclaimer":null,"include_ai_disclaimer":false,"apply_with_seek":null,"show_quick_apply_cta":true,"ai_opt_out_request_url":"http://app2.greenhouse.io/ai_opt_out_request/job_post/8441647002/ai_opt_out","education_config":{"id":8346283002,"school_name":"hidden","degree":"hidden","discipline":"hidden","start_month":"hidden","start_year":"hidden","end_month":"hidden","end_year":"hidden"},"questions":[{"required":true,"label":"First Name","description":null,"fields":[{"name":"first_name","type":"input_text"}]},{"required":true,"label":"Last Name","description":null,"fields":[{"name":"last_name","type":"input_text"}]},{"required":true,"label":"Email","description":null,"fields":[{"name":"email","type":"input_text"}]},{"required":true,"label":"Phone","description":null,"fields":[{"name":"phone","type":"input_text"}]},{"required":true,"label":"Candidate Location","description":null,"fields":[{"name":"candidate_location","type":"input_text"}]},{"required":true,"label":"Resume/CV","description":null,"fields":[{"name":"resume","type":"input_file","allowed_filetypes":["pdf","doc","docx","txt","rtf"]},{"name":"resume_text","type":"textarea"}]},{"required":false,"label":"Cover Letter","description":null,"fields":[{"name":"cover_letter","type":"input_file","allowed_filetypes":["pdf","doc","docx","txt","rtf"]},{"name":"cover_letter_text","type":"textarea"}]},{"required":true,"label":"Current Employer","description":null,"fields":[{"name":"question_35508020002","type":"input_text"}],"multi_select_style":"checkbox"},{"required"