_apply":false,"display_departments":true,"display_search_bar":true,"display_new_jobs_tag":true,"display_number_of_open_jobs":true,"display_footer":true,"candidate_portal_enabled":true,"application_tracking_enabled":false,"seek_id":"","enable_recruitics":true,"appcast_tracking_code":null,"google_drive_enabled":true,"enable_dropbox":true,"allow_external_notifications":true,"display_job_trust_profiles":false,"grayscale_ai_bot_enabled":false,"grayscale_ai_bot_access_token":null},"urlToken":"careem","embedded":false,"isJobPost":true},"routes/$url_token_.jobs_.$job_post_id":{"jobPost":{"post_type":"job_post","language":"en","title":"Captain Acquisition Lead","hiring_plan_id":6076794002,"content":"\u003cp\u003e\u003cstrong\u003eAbout the Team\u003c/strong\u003e\u003cbr\u003eThe Captain Acquisition \u0026amp; Market Operations team is the driving force behind our supply growth in Saudi Arabia. The team plays a pivotal role in building and managing the supply base—from onboarding third-party logistics (3PL) partners to ensuring captain (driver) availability and operational readiness. Acting as the central hub for supplier coordination, captain onboarding, and ramp-up activities, the team ensures that our markets are fully equipped to meet demand and deliver exceptional service.\u003c/p\u003e\n\u003cp\u003e\u003cstrong\u003eWhat you'll do\u003c/strong\u003e\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003eOwn and lead the full captain acquisition process.\u003c/li\u003e\n\u003cli\u003eInitiate and manage onboarding conversations with 3PL partners and logistics suppliers\u003c/li\u003e\n\u003cli\u003eAlign captain supply with Careem's growth plans by ensuring 3PLs meet their commitments.\u003c/li\u003e\n\u003cli\u003eTrack and enforce fulfilment targets.\u003c/li\u003e\n\u003cli\u003eDistribute captain swag/uniforms and coordinate training initiatives.\u003c/li\u003e\n\u003cli\u003eBuild and nurture relationships with 3PL providers to establish trust and long-term collaboration.\u003c/li\u003e\n\u003cli\u003eServe as the point of contact for resolving operational issues with suppliers and captains.\u003c/li\u003e\n\u003cli\u003eMaintain clear documentation and reporting of acquisition progress and supply health.\u003c/li\u003e\n\u003c/ul\u003e\n\u003cp\u003e\u003cstrong\u003eWhat you'll need\u003c/strong\u003e\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003e5–7 years of experience in acquisition, logistics, or operations in a fast-moving environment (e.g., food tech, q-commerce, mobility)\u003c/li\u003e\n\u003cli\u003eProven track record of last mile operations or supplier/vendor management\u003c/li\u003e\n\u003cli\u003eExcellent communication and stakeholder management skills.\u003c/li\u003e\n\u003cli\u003eIntermediate Excel/Google Sheets proficiency required; SQL is a plus.\u0026nbsp;\u003c/li\u003e\n\u003cli\u003eAnalytical mindset with comfort handling numbers and supply metrics.\u003c/li\u003e\n\u003cli\u003eProficiency in Arabic \u0026amp; English.\u003c/li\u003e\n\u003cli\u003eEntrepreneurial spirit and adaptability to thrive in a dynamic, fast-paced environment.\u003c/li\u003e\n\u003cli\u003eDemonstrated ability to lead cross-functional projects independently.\u003c/li\u003e\n\u003cli\u003eBased in Riyadh.\u003c/li\u003e\n\u003c/ul\u003e\n\u003cp\u003e\u003cstrong\u003eWhat we’ll provide you\u003c/strong\u003e\u003c/p\u003e\n\u003cp\u003eWe offer colleagues the opportunity to drive impact in the region while they learn and grow. As a full time Careem colleague, you will be able to:\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003eWork and learn from great minds by joining a community of inspiring colleagues.\u003c/li\u003e\n\u003cli\u003ePut your passion to work in a purposeful organisation dedicated to creating impact in a region with a lot of untapped potential.\u003c/li\u003e\n\u003cli\u003eExplore new opportunities to learn and grow every day.\u003c/li\u003e\n\u003cli\u003eWork 4 days a week in office \u0026amp; 1 day from home, and remotely from any country in the world for 30 days a year with unlimited vacation days per year. (If you are in an individual contributor role in tech, you will have 2 office days a week and 3 to work from home.)\u003c/li\u003e\n\u003cli\u003eAccess to healthcare benefits and fitness reimbursements for health activities including gym, health club, and training classes.\u003c/li\u003e\n\u003c/ul\u003e\n\u003cp\u003e\u0026nbsp;\u003c/p\u003e","introduction":"\u003cp\u003e\u003cspan style=\"font-family: helvetica, arial, sans-serif; font-size: 12pt;\"\u003eCareem is building the Everything App for the greater Middle East — making it easy to move around, order food and groceries, manage payments, and more. Our purpose is simple: to simplify and improve people’s lives and build an awesome organisation that inspires.\u003c/span\u003e\u003cbr\u003e\u003cspan style=\"font-family: helvetica, arial, sans-serif; font-size: 12pt;\"\u003eSince 2012, Careem has enabled earnings for over 2.5 million Captains, simplified the lives of more than 70 million customers, and built a platform where the region’s best talent and entrepreneurs thrive. We operate in 70+ cities across 10 countries, from Morocco to Pakistan.\u003c/span\u003e\u003c/p\u003e\n\u003cp\u003e\u003cspan style=\"font-family: helvetica, arial, sans-serif; font-size: 12pt;\"\u003e\u003cstrong data-stringify-type=\"bold\"\u003e\u003cem data-stringify-type=\"italic\"\u003eWe’re now entering our next chapter — one powered by AI. We’re looking for AI talent: curious problem-solvers who know how to apply AI to build tools, automate workflows, and create real impact. Whether it’s streamlining operations, enhancing customer experience, or reimagining internal systems — we want people who can make Careem work smarter and move faster.\u003c/em\u003e\u003c/strong\u003e\u003c/span\u003e\u003c/p\u003e","conclusion":"","enable_eeoc":false,"job_post_location":"Riyadh, Saudi Arabia","public_url":"https://boards.greenhouse.io/careem/jobs/7804444002?gh_jid=7804444002","company_name":"Careem","confirmation_message":"\u003cp\u003eWe are thrilled that you are interested to be part of Careem!\u003cbr\u003e\u003cbr\u003eWe have received your application and one of our Recruiters will review it. Due to the volume of applications, we are unable to give a response to all applications, and prioritize the ones that meet the role requirements. Check out our careers page for the role that may be the best match for your experience - www.careem.com/careers\u003c/p\u003e\n\u003cp\u003eTalent Acquisition | Careem\u003c/p\u003e\n\u003cp\u003e\u0026nbsp;\u003c/p\u003e","pay_ranges":[],"published_at":"2025-08-07T04:37:42-04:00","employment":"hidden","fingerprint":"5fda7cad8814aab70cef45d82536417c06f74ce0","redirect_to":null,"is_featured":false,"ai_disclaimer":null,"include_ai_disclaimer":false,"apply_with_seek":null,"show_quick_apply_cta":true,"ai_opt_out_request_url":"http://app2.greenhouse.io/ai_opt_out_request/job_post/7804444002/ai_opt_out","education_config":{"id":7722741002,"school_name":"hidden","degree":"hidden","discipline":"hidden","start_month":"hidden","start_year":"hidden","end_month":"hidden","end_year":"hidden"},"questions":[{"required":true,"label":"First Name","description":null,"fields":[{"name":"first_name","type":"input_text"}]},{"required":true,"label":"Last Name","description":null,"fields":[{"name":"last_name","type":"input_text"}]},{"required":true,"label":"Email","description":null,"fields":[{"name":"email","type":"input_text"}]},{"required":true,"label":"Phone","description":null,"fields":[{"name":"phone","type":"input_text"}]},{"required":true,"label":"Candidate Location","description":null,"fields":[{"name":"candidate_location","type":"input_text"}]},{"required":true,"label":"Resume/CV","description":null,"fields":[{"name":"resume","type":"input_file","allowed_filetypes":["pdf","doc","docx","txt","rtf"]},{"name":"resume_text","type":"textarea"}]},{"required":false,"label":"Cover Letter","desc