","LOTUS_GIT_COMMIT":"9d3ab97d7ce8a9ec7b0f3ba14d84f1b9924ed029","MAX_POSTS_PER_PAGE":50,"ROLLBAR_ENV":"production","ROLLBAR_FE_ENABLED":true,"ROLLBAR_POST_CLIENT_ITEM_TOKEN":"fb557f59a5a84ab788801dd742eacf34","ROLLBAR_FILTER_HYDRATION_ERRORS":true,"GOOGLE_PICKER_APP_ID":"594601915089","GOOGLE_PICKER_DEVELOPER_KEY":"AIzaSyBeoz4WOjOsy8ZJFIkkQBvL8BZQCzLplHQ","GOOGLE_PICKER_CLIENT_ID":"594601915089-7c2994029qkt5qu2tmbppujr9jqrqqrs.apps.googleusercontent.com","DROPBOX_CHOOSER_API_KEY":"mh9jyh4mfwjnfhj","GOOGLE_RECAPTCHA_INVISIBLE_KEY":"6LfmcbcpAAAAAChNTbhUShzUOAMj_wY9LQIvLFX0","GOOGLE_RECAPTCHA_ENDPOINT":"https://www.recaptcha.net/recaptcha/enterprise.js","JOB_SEEKERS_URL":"https://my.greenhouse.io","SNOWPLOW_APP_ID":"job-board-renderer","SNOWPLOW_ENABLED":true,"SNOWPLOW_ENDPOINT":"spl.greenhouse.io","SNOWPLOW_NAMESPACE":"job-board-renderer-tracker","SNOWPLOW_DEBUG":false},"boardConfiguration":{"job_board_id":4001440002,"logo":{"href":"https://www.careem.com/","url":"https://s2-recruiting.cdn.greenhouse.io/external_greenhouse_job_boards/logos/400/144/000/original/Careem_Newbranding_CareemLogo_1024x512.jpg?1683707025"},"filters":{"include_office_filter":true,"include_department_filter":true,"allow_custom_field_filters":false},"button_shape":"pill","cta_text":"Apply","primary_font":"Untitled Sans","secondary_font":"Untitled Sans","custom_primary_font_url":null,"custom_secondary_font_url":null,"dropdown_selection_color":"#c4d6f3","active_field_color":"#709ce2","link_color":"#3d74cc","list_selection_color":"#d5e2f6","primary_font_color":"#3d74cc","outside_label":false,"view_all_link":false,"button_color":"#578bdd","button_hover_color":"#709ce2","button_text_color":"#000000","banner_url":null,"board_layout":"stacked","display_department_hierarchy":true,"hide_app_description":false,"header_text":"Current openings at Careem","job_board_public_url":"https://jobs.careem.com/","secondary_font_color":"#262626","background_color":"#ffffff","disable_captcha":false,"disable_eeoc_quick_apply":false,"display_departments":true,"display_search_bar":true,"display_new_jobs_tag":true,"display_number_of_open_jobs":true,"display_footer":true,"candidate_portal_enabled":true,"application_tracking_enabled":false,"seek_id":"","enable_recruitics":true,"appcast_tracking_code":null,"google_drive_enabled":true,"enable_dropbox":true,"allow_external_notifications":true,"display_job_trust_profiles":false,"grayscale_ai_bot_enabled":false,"grayscale_ai_bot_access_token":null},"urlToken":"careem","embedded":false,"isJobPost":true},"routes/$url_token_.jobs_.$job_post_id":{"jobPost":{"post_type":"job_post","language":"en","title":"Captain Performance \u0026 Engagement Manager","hiring_plan_id":6337517002,"content":"\u003cp\u003e\u003c/p\u003e\n\u003cdiv\u003e\u003cstrong\u003eAbout the role\u003c/strong\u003e\u003cbr\u003eThe \u003cstrong\u003ePerformance \u0026amp; Engagement Manager\u003c/strong\u003e is a hybrid strategic-technical role responsible for the health, efficiency, and growth of our marketplace supply. You will transition our logistics operations from manual oversight to \u003cstrong\u003edata-driven excellence\u003c/strong\u003e. By leveraging \u003cstrong\u003eAI methodologies\u003c/strong\u003e and \u003cstrong\u003edeep business acumen\u003c/strong\u003e, you will plan supply capacity, optimize captain performance, and \"cure\" marketplace imbalances through sophisticated engagement strategies.\u003c/div\u003e\n\u003cdiv\u003e\u003cbr\u003e\u003cstrong\u003eWhat you'll do\u0026nbsp;\u003c/strong\u003e\u003c/div\u003e\n\u003cul data-list-tree=\"true\" data-indent=\"0\" data-border=\"0\"\u003e\n\u003cli\u003e\u003cstrong\u003eStrategic Supply Planning:\u003c/strong\u003e Move beyond daily scheduling to long-term capacity forecasting. Use predictive modeling to ensure the fleet size matches projected demand, preventing both under-supply and over-saturation.\u003c/li\u003e\n\u003cli\u003e\u003cstrong\u003eAI \u0026amp; Performance Optimization:\u003c/strong\u003e Implement and oversee AI-driven tools for captain scoring, churn prediction, and automated incentive structures. You will translate complex data into actionable \"cures\" for low-performing zones.\u003c/li\u003e\n\u003cli\u003e\u003cstrong\u003eNext-Gen Engagement:\u003c/strong\u003e Design and manage the \"Captain Lifecycle.\" Create data-backed loyalty programs, gamification frameworks, and communication loops that keep partners engaged and retained.\u003c/li\u003e\n\u003cli\u003e\u003cstrong\u003eData-Driven \"Diagnosis\":\u003c/strong\u003e Monitor KPIs (Acceptance Rates, Fulfillment, Shift Adherence, and Retention). You are expected to identify \u003cem\u003ewhy\u003c/em\u003e a metric is failing and design the technical or operational intervention to fix it.\u003c/li\u003e\n\u003cli\u003e\u003cstrong\u003eFleet Partner \u0026amp; Stakeholder Relations:\u003c/strong\u003e Maintain high-level relationships with fleet partners and supervisors in Jordan, ensuring that central AI-driven strategies are executed effectively on the ground.\u003c/li\u003e\n\u003cli\u003e\u003cstrong\u003eBudget \u0026amp; Incentive ROI:\u003c/strong\u003e Manage the engagement budget with a focus on ROI. You will optimize spend by using data to target incentives where they have the highest impact on marketplace liquidity.\u003c/li\u003e\n\u003cli\u003e\u003cstrong\u003eCross-Functional Bridge:\u003c/strong\u003e Act as the Amman-based expert for the Central Team, ensuring that global product features and algorithms are localized and functioning correctly within the Jordan market.\u003c/li\u003e\n\u003c/ul\u003e\n\u003cdiv\u003e\n\u003cp\u003e\u003cstrong\u003eWhat you'll need\u0026nbsp;\u003c/strong\u003e\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003e\u003cstrong\u003eEducation:\u003c/strong\u003e Bachelor’s degree in Engineering, Data Science, Supply Chain, or Business (with a heavy analytical focus).\u003c/li\u003e\n\u003cli\u003e\u003cstrong\u003eExperience:\u003c/strong\u003e 5+ years in high-growth tech, marketplace operations, or logistics.\u003c/li\u003e\n\u003cli\u003e\u003cstrong\u003eAI \u0026amp; Technical Skills:\u003c/strong\u003e Practical understanding of how \u003cstrong\u003eMachine Learning\u003c/strong\u003e affects marketplace dynamics (e.g., how algorithms impact dispatch or pricing).\u003c/li\u003e\n\u003cli\u003eAdvanced \u003cstrong\u003eSQL\u003c/strong\u003e is mandatory; experience with \u003cstrong\u003ePython\u003c/strong\u003e or \u003cstrong\u003eR\u003c/strong\u003e for data modeling is highly preferred plus technical grip on AI command.\u003c/li\u003e\n\u003cli\u003eExperience with BI tools (Tableau/Looker/G-sheets/Data-Studio) to build \"Health Dashboards.\"\u003c/li\u003e\n\u003cli\u003e\u003cstrong\u003eBusiness Acumen:\u003c/strong\u003e The ability to connect a 5% drop in captain engagement to a specific dollar loss in revenue, and the creative thinking to solve it. Beyond operational metrics, you must understand the financial heartbeat of the marketplace (supply + demand).\u003c/li\u003e\n\u003cli\u003e\u003cstrong\u003eLeadership and Stakeholder Management :\u003c/strong\u003e Proven ability to mentor supervisors and influence external partners through data-backed persuasion rather than just administrative authority.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/div\u003e\n\u003cp\u003e\u003cstrong\u003eWhat we’ll provide you\u003c/strong\u003e\u003c/p\u003e\n\u003cp\u003eWe offer colleagues the opportunity to drive impact in the region while they learn and grow. As a full time Careem colleague, you will be able to:\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003eWork and learn from great minds by joining a community of inspiring colleagues.\u003c/li\u003e\n\u003cli\u003ePut your passion to work in a purposeful organisation dedicated to creating impact in a region with a lot of untapped potential.\u003c/li\u003e\n\u003cli\u003eExplore new opportunities to learn and grow every day.\u003c/li\u003e\n\u003cli\u003eWork 4 days a week in office \u0026amp; 1 day from home, and remotely from any country in the world for 30 days a year with unlimited vacation days per year. (If you are in an individual contributor role in tech, you will have 2 office days a week and 3 to work from home.)\u003c/li\u003e\n\u003cli\u003eAccess to healthcare benefits and fitness reimbursements for health activities including gym, health club, and training classes.\u003c/li\u003e\n\u003c/ul\u003e\n\u003cp\u003e\u0026nbsp;\u003c/p\u003e","introduction":"\u003cp\u003e\u003cspan style=\"font-family: helvetica, arial, sans-serif; font-size: 12pt;\"\u003eCareem is building the Everything App for the greater Middle East — making it easy to move around, order food and groceries, manage payments, and more. Our purpose is simple: to simplify and improve people’s lives and build an awesome organisation that inspires.\u003c/span\u003e\u003cbr\u003e\u003cspan style=\"font-family: helvetica, arial, sans-serif; font-size: 12pt;\"\u003eSince 2012, Careem has enabled earnings for over 2.5 million Captains, simplified the lives of more than 70 million customers, and built a platform where the region’s best talent and entrepreneurs thrive. We operate in 70+ cities across 10 countries, from Morocco to Pakistan.\u003c/span\u003e\u003c/p\u003e\n\u003cp\u003e\u003cspan style=\"font-family: helvetica, arial, sans-serif; font-size: 12pt;\"\u003e\u003cstrong data-stringify-type=\"bold\"\u003e\u003cem data-stringify-type=\"italic\"\u003eWe’re now entering our next chapter — one powered by AI. We’re looking for AI talent: curious problem-solvers who know how to apply AI to build tools, automate workflows, and create real impact. Whether it’s streamlining operations, enhancing customer experience, or reimagining internal systems — we want people who can make Careem work smarter and move faster.\u003c/em\u003e\u003c/strong\u003e\u003c/span\u003e\u003c/p\u003e","conclusion":"","enable_eeoc":false,"job_post_location":"Amman, Jordan","public_url":"https://boards.greenhouse.io/careem/jobs/8358326002?gh_jid=8358326002","company_name":"Careem","confirmation_message":"\u003cp\u003eWe are thrilled that you are interested to be part of Careem!\u003cbr\u003e\u003cbr\u003eWe have received your application and one of our Recruiters will review it. Due to the volume of applications, we are unable to give a response to all applications, and prioritize the ones that meet the role requirements. Check out our careers page for the role that may be the best match for your experience - www.careem.com/careers\u003c/p\u003e\n\u003cp\u003eTalent Acquisition | Careem\u003c/p\u003e\n\u003cp\u003e\u0026nbsp;\u003c/p\u003e","pay_ranges":[],"published_at":"2026-02-02T07:00:41-05:00","employment":"hidden","fingerprint":"464b6b303154e1a1290b070c612320a2709ed357","redirect_to":null,"is_featured":false,"ai_disclaimer":null,"include_ai_disclaimer":false,"apply_with_seek":null,"show_quick_apply_cta":true,"ai_opt_out_request_url":"http://app2.greenhouse.io/ai_opt_out_request/job_post/8358326002/ai_opt_out","education_config":{"id":8265006002,"school_name":"hidden","degree":"hidden","discipline":"hidden","start_month":"hidden","start_year":"hidden","end_month":"hidden","end_year":"hidden"},"questions":[{"required":true,"label":"First Name","description":null,"fields":[{"name":"first_name","type":"input_text"}]},{"required":true,"label":"Last Name","description":null,"fields":[{"name":"last_name","type":"input_text"}]},{"required":true,"label":"Email","description":null,"fields":[{"name":"email","type":"input_text"}]},{"required":true,"label":"Phone","description":null,"fields":[{"name":"phone","type":"input_text"}]},{"required":true,"label":"Candidate Location","description":null,"fields":[{"name":"candidate_location","type":"input_text"}]},{"required":true,"label":"Resume/CV","description":null,"fields":[{"name":"resume","type":"input_file","allowed_filetypes":["pdf","doc","docx","txt","rtf"]},{"name":"resume_text","type":"