_apply":false,"display_departments":true,"display_search_bar":true,"display_new_jobs_tag":true,"display_number_of_open_jobs":true,"display_footer":true,"candidate_portal_enabled":true,"application_tracking_enabled":false,"seek_id":"","enable_recruitics":true,"appcast_tracking_code":null,"google_drive_enabled":true,"enable_dropbox":true,"allow_external_notifications":true,"display_job_trust_profiles":false,"grayscale_ai_bot_enabled":false,"grayscale_ai_bot_access_token":null},"urlToken":"careem","embedded":false,"isJobPost":true},"routes/$url_token_.jobs_.$job_post_id":{"jobPost":{"post_type":"job_post","language":"en","title":"Commercial Lead - Logistics","hiring_plan_id":6352719002,"content":"\u003cp\u003e\u003cstrong\u003eAbout The Role\u003c/strong\u003e\u003cbr\u003eCareem Express is a vertical within the Careem ecosystem – a startup within a startup. We are responsible for fulfillment and last mile delivery for hundreds of merchants in a variety of industries, including e-commerce, food, grocery, and other areas. We are a small and passionate team that is building the next big vertical for Careem. Commercial lead is at the core of Careem Express. They are our face to clients, and we rely on them to build a strong relationship with enterprises and important clients \u0026amp; build on our strong pipeline targeting food \u0026amp; Non-food clients. They are responsible for growing existing Tier 1 clients and bringing in demand in a sustainable way.\u003c/p\u003e\n\u003cdiv\u003e\u003cstrong\u003eWhat You’ll Do\u003c/strong\u003e\u003c/div\u003e\n\u003cul\u003e\n\u003cli\u003eBusiness development - Acquire new accounts across KSA (prospecting, targeting, pitching, contract negotiations, go-live)\u003c/li\u003e\n\u003cli\u003eBuild and manage relationships with existing clients\u003c/li\u003e\n\u003cli\u003eAchieve monthly Revenue targets through existing and new B2B clients\u003c/li\u003e\n\u003cli\u003eCommercial understanding and handling negotiations with clients\u003c/li\u003e\n\u003cli\u003eCoordinate with operations / logistics team internally for support to make sure that the pitches are made at the right commercials\u003c/li\u003e\n\u003cli\u003eCoordinate with Legal internally for contract closures\u003c/li\u003e\n\u003c/ul\u003e\n\u003cdiv\u003e\u003cstrong\u003eWhat You’ll Need\u003c/strong\u003e\u003c/div\u003e\n\u003cul\u003e\n\u003cli\u003e2-3 years of Account Management/Sales experience from Food \u0026amp; Non-food B2B, Ecommerce or on-demand logistics industry\u003c/li\u003e\n\u003cli\u003eHigh performer – track record of generating revenue for businesses\u003c/li\u003e\n\u003cli\u003eBusiness development mindset coupled with Operational detail orientation\u003c/li\u003e\n\u003cli\u003eTarget oriented \u0026amp; Problem solver\u003c/li\u003e\n\u003cli\u003eEnergetic and excited about joining a startup environment\u003c/li\u003e\n\u003c/ul\u003e\n\u003cp\u003e\u003cstrong\u003eWhat we’ll provide you\u003c/strong\u003e\u003c/p\u003e\n\u003cp\u003eWe offer colleagues the opportunity to drive impact in the region while they learn and grow. As a full time Careem colleague, you will be able to:\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003eWork and learn from great minds by joining a community of inspiring colleagues.\u003c/li\u003e\n\u003cli\u003ePut your passion to work in a purposeful organisation dedicated to creating impact in a region with a lot of untapped potential.\u003c/li\u003e\n\u003cli\u003eExplore new opportunities to learn and grow every day.\u003c/li\u003e\n\u003cli\u003eWork 4 days a week in office \u0026amp; 1 day from home, and remotely from any country in the world for 30 days a year with unlimited vacation days per year. (If you are in an individual contributor role in tech, you will have 2 office days a week and 3 to work from home.)\u003c/li\u003e\n\u003cli\u003eAccess to healthcare benefits and fitness reimbursements for health activities including gym, health club, and training classes.\u003c/li\u003e\n\u003c/ul\u003e\n\u003cp\u003e\u0026nbsp;\u003c/p\u003e","introduction":"\u003cp\u003e\u003cspan style=\"font-family: helvetica, arial, sans-serif; font-size: 12pt;\"\u003eCareem is building the Everything App for the greater Middle East — making it easy to move around, order food and groceries, manage payments, and more. Our purpose is simple: to simplify and improve people’s lives and build an awesome organisation that inspires.\u003c/span\u003e\u003cbr\u003e\u003cspan style=\"font-family: helvetica, arial, sans-serif; font-size: 12pt;\"\u003eSince 2012, Careem has enabled earnings for over 2.5 million Captains, simplified the lives of more than 70 million customers, and built a platform where the region’s best talent and entrepreneurs thrive. We operate in 70+ cities across 10 countries, from Morocco to Pakistan.\u003c/span\u003e\u003c/p\u003e\n\u003cp\u003e\u003cspan style=\"font-family: helvetica, arial, sans-serif; font-size: 12pt;\"\u003e\u003cstrong data-stringify-type=\"bold\"\u003e\u003cem data-stringify-type=\"italic\"\u003eWe’re now entering our next chapter — one powered by AI. We’re looking for AI talent: curious problem-solvers who know how to apply AI to build tools, automate workflows, and create real impact. Whether it’s streamlining operations, enhancing customer experience, or reimagining internal systems — we want people who can make Careem work smarter and move faster.\u003c/em\u003e\u003c/strong\u003e\u003c/span\u003e\u003c/p\u003e","conclusion":"","enable_eeoc":false,"job_post_location":"Riyadh, Saudi Arabia","public_url":"https://boards.greenhouse.io/careem/jobs/8398003002?gh_jid=8398003002","company_name":"Careem","confirmation_message":"\u003cp\u003eWe are thrilled that you are interested to be part of Careem!\u003cbr\u003e\u003cbr\u003eWe have received your application and one of our Recruiters will review it. Due to the volume of applications, we are unable to give a response to all applications, and prioritize the ones that meet the role requirements. Check out our careers page for the role that may be the best match for your experience - www.careem.com/careers\u003c/p\u003e\n\u003cp\u003eTalent Acquisition | Careem\u003c/p\u003e\n\u003cp\u003e\u0026nbsp;\u003c/p\u003e","pay_ranges":[],"published_at":"2026-03-12T10:37:10-04:00","employment":"hidden","fingerprint":"21aead92285f12fa3960ff33fd598280b1b0d123","redirect_to":null,"is_featured":false,"ai_disclaimer":null,"include_ai_disclaimer":false,"apply_with_seek":null,"show_quick_apply_cta":true,"ai_opt_out_request_url":"http://app2.greenhouse.io/ai_opt_out_request/job_post/8398003002/ai_opt_out","education_config":{"id":8304062002,"school_name":"hidden","degree":"hidden","discipline":"hidden","start_month":"hidden","start_year":"hidden","end_month":"hidden","end_year":"hidden"},"questions":[{"required":true,"label":"First Name","description":null,"fields":[{"name":"first_name","type":"input_text"}]},{"required":true,"label":"Last Name","description":null,"fields":[{"name":"last_name","type":"input_text"}]},{"required":true,"label":"Email","description":null,"fields":[{"name":"email","type":"input_text"}]},{"required":true,"label":"Phone","description":null,"fields":[{"name":"phone","type":"input_text"}]},{"required":true,"label":"Candidate Location","description":null,"fields":[{"name":"candidate_location","type":"input_text"}]},{"required":true,"label":"Resume/CV","description":null,"fields":[{"name":"resume","type":"input_file","allowed_filetypes":["pdf","doc","docx","txt","rtf"]},{"name":"resume_text","type":"textarea"}]},{"required":false,"label":"Cover Letter","description":null,"fields":[{"name":"cover_letter","type":"input_file","allowed_filetypes":["pdf","doc","docx","txt","rtf"]},{"name":"cover_letter_text","type":"textarea"}]},{"required":true,"label":"Current Employer","description":null,"fields":[{"name":"question_35102871002","type":"input_text"}],"multi_select_style":"checkbox"},{"required":true,"label":"Current Job Title